example.code:
# Avoid: static content as a Tool
@server.tool()
async def get_doc_index() -> str:
    """Returns the docs index (50KB)."""
    return load_all_docs_index()

# Better: expose as a Resource
@server.resource("docs://_index")
async def get_doc_index() -> str:
    return load_all_docs_index()

# Avoid: Resource with side effects
@server.resource("runbook://incident-foo")
async def get_runbook(incident: str) -> str:
    start_incident_playbook(incident)  # MUTATING!
    return load_runbook(incident)

# Better: expose as a Tool
@server.tool()
async def start_runbook(name: str) -> dict:
    """Start an incident runbook. MUTATING."""
    return start_incident_playbook(name)

@server.resource("runbook://{name}")
async def get_runbook(name: str) -> str:
    return load_runbook(name)  # Read-only

# Avoid: Tool the user is expected to invoke
@server.tool()
async def initialize_project(name: str) -> dict:
    """Initialize a new project."""
    # User expects to call this, but the model decides to call tools, not the user
    return setup_project(name)

# Better: expose as a Prompt
@server.prompt()
async def initialize_project(name: str) -> list[dict]:
    return [{"role": "user", "content": f"Initialize new project '{name}'. ..."}]

# Avoid: modes confuse the model
@server.tool()
async def exec(mode: str, target: str, content: str = None) -> str:
    if mode == "read": return read_file(target)
    if mode == "write": return write_file(target, content)
    if mode == "delete": return delete_file(target)

# Better: split into named tools
@server.tool()
async def read_file(path: str) -> str:
    return read_file_impl(path)

@server.tool()
async def write_file(path: str, content: str) -> dict:
    """MUTATING: write file."""
    return write_file_impl(path, content)

@server.tool()
async def delete_file(path: str) -> dict:
    """MUTATING: delete file."""
    return delete_file_impl(path)
